import { db } from './db';
import { User, Ad, Banner } from '../types';

// Simulate API delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const api = {
  // Auth
  login: async (phone: string, name?: string): Promise<User> => {
    await delay(500);
    const users = db.getUsers();
    let user = users.find(u => u.phone === phone);

    if (!user) {
      if (!name) throw new Error("المستخدم غير موجود، يرجى إدخال الاسم للتسجيل");
      user = {
        id: Math.random().toString(36).substr(2, 9),
        phone,
        name,
        role: 'USER',
        createdAt: new Date().toISOString()
      };
      db.saveUsers([...users, user]);
    }

    db.setCurrentUser(user);
    return user;
  },

  logout: () => {
    db.setCurrentUser(null);
  },

  // Ads
  getAds: async (): Promise<Ad[]> => {
    await delay(300);
    return db.getAds();
  },

  createAd: async (adData: Partial<Ad>): Promise<Ad> => {
    await delay(500);
    const currentUser = db.getCurrentUser();
    if (!currentUser) throw new Error("يجب تسجيل الدخول أولاً");

    const newAd: Ad = {
      id: Math.random().toString(36).substr(2, 9),
      title: adData.title || '',
      description: adData.description || '',
      price: adData.price || 0,
      category: adData.category || 'عام',
      image: adData.image || 'https://picsum.photos/seed/default/800/600',
      userId: currentUser.id,
      userName: currentUser.name,
      isFeatured: false,
      createdAt: new Date().toISOString()
    };

    const ads = db.getAds();
    db.saveAds([newAd, ...ads]);
    return newAd;
  },

  deleteAd: async (adId: string) => {
    const ads = db.getAds();
    db.saveAds(ads.filter(a => a.id !== adId));
  },

  toggleFeatured: async (adId: string) => {
    const ads = db.getAds();
    const updatedAds = ads.map(ad => 
      ad.id === adId ? { ...ad, isFeatured: !ad.isFeatured } : ad
    );
    db.saveAds(updatedAds);
  },

  // Banners
  getBanners: async (): Promise<Banner[]> => {
    return db.getBanners();
  },

  // Admin Only
  getAllUsers: async (): Promise<User[]> => {
    return db.getUsers();
  }
};

