import React, { useState, useEffect } from 'react';
import { Banner } from '../types';

interface BannerSliderProps {
  banners: Banner[];
}

const BannerSlider: React.FC<BannerSliderProps> = ({ banners }) => {
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    if (banners.length <= 1) return;
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % banners.length);
    }, 5000);
    return () => clearInterval(interval);
  }, [banners.length]);

  if (banners.length === 0) return null;

  return (
    <div className="relative w-full h-48 md:h-80 overflow-hidden rounded-2xl shadow-lg bg-gray-200">
      {banners.map((banner, index) => (
        <div
          key={banner.id}
          className={`absolute inset-0 transition-all duration-700 ease-in-out transform ${
            index === currentIndex ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-full'
          }`}
        >
          <img
            src={banner.image}
            alt={banner.title}
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent flex items-end p-8">
            <div className="text-white">
              <h2 className="text-2xl md:text-4xl font-bold mb-2">{banner.title}</h2>
              <p className="text-white/80 text-sm md:text-base">اكتشف أفضل العروض اليومية وحصرياً على منصتنا</p>
            </div>
          </div>
        </div>
      ))}

      {/* Navigation Dots */}
      <div className="absolute bottom-4 left-1/2 transform -translate-x-1/2 flex space-x-reverse space-x-2">
        {banners.map((_, index) => (
          <button
            key={index}
            onClick={() => setCurrentIndex(index)}
            className={`w-2.5 h-2.5 rounded-full transition-all ${
              index === currentIndex ? 'bg-white w-8' : 'bg-white/40'
            }`}
          />
        ))}
      </div>
    </div>
  );
};

export default BannerSlider;

import React, { useEffect, useState } from 'react';
import { api } from '../services/api';
import { Ad, Banner } from '../types';
import BannerSlider from '../components/BannerSlider';
import AdCard from '../components/AdCard';

const Home: React.FC = () => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [banners, setBanners] = useState<Banner[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState('الكل');

  const categories = ['الكل', 'إلكترونيات', 'سيارات', 'عقارات', 'أثاث', 'وظائف'];

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [adsData, bannersData] = await Promise.all([
          api.getAds(),
          api.getBanners()
        ]);
        setAds(adsData);
        setBanners(bannersData.filter(b => b.active));
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const filteredAds = activeCategory === 'الكل' 
    ? ads 
    : ads.filter(ad => ad.category === activeCategory);

  const featuredAds = filteredAds.filter(ad => ad.isFeatured);
  const normalAds = filteredAds.filter(ad => !ad.isFeatured);

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-12 flex justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Banner Section */}
      <div className="mb-12">
        <BannerSlider banners={banners} />
      </div>

      {/* Categories Bar */}
      <div className="flex gap-4 overflow-x-auto pb-6 mb-8 no-scrollbar scroll-smooth">
        {categories.map((cat) => (
          <button
            key={cat}
            onClick={() => setActiveCategory(cat)}
            className={`px-6 py-2 rounded-full whitespace-nowrap text-sm font-semibold transition shadow-sm ${
              activeCategory === cat 
                ? 'bg-blue-600 text-white' 
                : 'bg-white text-gray-600 hover:bg-gray-50'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* Featured Ads Section */}
      {featuredAds.length > 0 && (
        <section className="mb-12">
          <div className="flex items-center gap-2 mb-6">
            <i className="fas fa-crown text-amber-500 text-xl"></i>
            <h2 className="text-xl font-bold text-gray-800">إعلانات مميزة</h2>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {featuredAds.map(ad => (
              <AdCard key={ad.id} ad={ad} />
            ))}
          </div>
        </section>
      )}

      {/* All Ads Grid */}
      <section>
        <div className="flex items-center gap-2 mb-6">
          <i className="fas fa-th-large text-blue-500 text-xl"></i>
          <h2 className="text-xl font-bold text-gray-800">أحدث الإعلانات</h2>
        </div>

        {normalAds.length === 0 ? (
          <div className="bg-white rounded-2xl p-12 text-center border">
            <div className="text-6xl text-gray-200 mb-4">
              <i className="fas fa-search"></i>
            </div>
            <p className="text-gray-500 font-medium">لا توجد إعلانات في هذا القسم حالياً</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {normalAds.map(ad => (
              <AdCard key={ad.id} ad={ad} />
            ))}
          </div>
        )}
      </section>
    </div>
  );
};

export default Home;

