import React, { useEffect, useState } from 'react';
import { api } from '../services/api';
import { Ad, User } from '../types';
import AdCard from '../components/AdCard';

const AdminDashboard: React.FC = () => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [view, setView] = useState<'ads' | 'users'>('ads');
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [adsData, usersData] = await Promise.all([
        api.getAds(),
        api.getAllUsers()
      ]);
      setAds(adsData);
      setUsers(usersData);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleToggleFeatured = async (id: string) => {
    await api.toggleFeatured(id);
    fetchData();
  };

  const handleDeleteAd = async (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الإعلان؟')) {
      await api.deleteAd(id);
      fetchData();
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">لوحة الإدارة</h1>
          <p className="text-gray-500">إدارة المحتوى والمستخدمين عبر المنصة</p>
        </div>

        <div className="bg-gray-100 p-1.5 rounded-xl flex">
          <button 
            onClick={() => setView('ads')}
            className={`px-6 py-2 rounded-lg font-bold transition ${view === 'ads' ? 'bg-white shadow text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            الإعلانات ({ads.length})
          </button>
          <button 
            onClick={() => setView('users')}
            className={`px-6 py-2 rounded-lg font-bold transition ${view === 'users' ? 'bg-white shadow text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            المستخدمين ({users.length})
          </button>
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-20">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      ) : view === 'ads' ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {ads.map(ad => (
            <AdCard 
              key={ad.id} 
              ad={ad} 
              isAdmin 
              onToggleFeatured={handleToggleFeatured}
              onDelete={handleDeleteAd}
            />
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-2xl border overflow-hidden">
          <table className="w-full text-right border-collapse">
            <thead className="bg-gray-50 border-b">
              <tr>
                <th className="p-4 font-bold text-gray-600">المستخدم</th>
                <th className="p-4 font-bold text-gray-600">رقم الهاتف</th>
                <th className="p-4 font-bold text-gray-600">الدور</th>
                <th className="p-4 font-bold text-gray-600">تاريخ الانضمام</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-gray-50 transition">
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold">
                        {user.name.charAt(0)}
                      </div>
                      <span className="font-semibold">{user.name}</span>
                    </div>
                  </td>
                  <td className="p-4 font-mono text-gray-500">{user.phone}</td>
                  <td className="p-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${user.role === 'ADMIN' ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                      {user.role === 'ADMIN' ? 'مدير' : 'مستخدم'}
                    </span>
                  </td>
                  <td className="p-4 text-gray-400 text-sm">
                    {new Date(user.createdAt).toLocaleDateString('ar-SA')}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

